#include <stdio.h>
#include <string.h>

struct Student {
    char name[51];
    int rollNumber;
    float marks;
};

void displayStudent(struct Student s) {
    printf("Name: %s\n", s.name);
    printf("Roll Number: %d\n", s.rollNumber);
    printf("Marks: %.2f\n", s.marks);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    int c;
    while ((c = getchar()) != '\n' && c != EOF); // consume end of line after T
    while (T--) {
        struct Student st;
        if (!fgets(st.name, sizeof(st.name), stdin)) break;
        st.name[strcspn(st.name, "\n")] = '\0';
        if (scanf("%d %f", &st.rollNumber, &st.marks) != 2) break;
        while ((c = getchar()) != '\n' && c != EOF); // consume end of line after numbers
        displayStudent(st);
    }
    return 0;
}

