    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string dummy;
    getline(cin, dummy); // consume end‑of‑line after T
    while (T--) {
        Student st;
        getline(cin, st.name);
        cin >> st.rollNumber >> st.marks;
        getline(cin, dummy); // consume end‑of‑line before next name
        displayStudent(st);
    }
    return 0;
