code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static class Student {
        String name;
        int rollNumber;
        float marks;
        Student(String n, int r, float m) { name = n; rollNumber = r; marks = m; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String firstLine = br.readLine();
        if (firstLine == null || firstLine.trim().isEmpty()) {
            // No input provided; nothing to do.
            return;
        }
        int T = Integer.parseInt(firstLine.trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String name = br.readLine();
            if (name == null) break;
            String rollLine = br.readLine();
            if (rollLine == null) break;
            String marksLine = br.readLine();
            if (marksLine == null) break;
            int roll = Integer.parseInt(rollLine.trim());
            float marks = Float.parseFloat(marksLine.trim());
            out.append("Name: ").append(name).append('\n');
            out.append("Roll Number: ").append(roll).append('\n');
            out.append(String.format(Locale.US, "Marks: %.2f", marks)).append('\n');
        }
        System.out.print(out.toString());
    }
}

